code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        x = int(data[idx]); idx += 1
        out.append("YES" if 555 * x <= 6060 else "NO")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

